import React, { useEffect } from 'react';

const Dealers = () => {
    // Logic for fetching or displaying dealers
    useEffect(() => {
        console.log("Dealers component mounted");
    }, []);

    return (
        <div style={{ padding: '40px', fontFamily: 'Arial' }}>
            <h1 style={{ color: '#6a1b9a' }}>Dealerships</h1>
            <table style={{ width: '100%', borderCollapse: 'collapse', marginTop: '20px' }}>
                <thead>
                    <tr style={{ backgroundColor: '#6a1b9a', color: 'white' }}>
                        <th style={{ padding: '10px', textAlign: 'left' }}>ID</th>
                        <th style={{ padding: '10px', textAlign: 'left' }}>Dealer Name</th>
                        <th style={{ padding: '10px', textAlign: 'left' }}>City</th>
                        <th style={{ padding: '10px', textAlign: 'left' }}>Address</th>
                        <th style={{ padding: '10px', textAlign: 'left' }}>Zip</th>
                        <th style={{ padding: '10px', textAlign: 'left' }}>State</th>
                    </tr>
                </thead>
                <tbody>
                    {/* Your mapped dealer rows will go here */}
                    <tr>
                        <td colSpan="6" style={{ padding: '20px', textAlign: 'center' }}>
                            Loading dealer data...
                        </td>
                    </tr>
                </tbody>
            </table>
        </div>
    );
};

export default Dealers;
